 1	import React, { FC } from 'react';
 2	
 3	import EnvironmentForm from '@kubevirt-utils/components/EnvironmentEditor/EnvironmentForm';
 4	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 5	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 6	import { Divider, Grid, GridItem, PageSection, PageSectionVariants } from '@patternfly/react-core';
 7	
 8	import { onSubmitYAML } from '../details/utils/utils';
 9	import { ConfigurationInnerTabProps } from '../utils/types';
10	
11	import DiskList from './components/tables/disk/DiskList';
12	
13	const StorageTab: FC<ConfigurationInnerTabProps> = ({ vm, vmi }) => (
14	  <SidebarEditor
15	    onResourceUpdate={onSubmitYAML}
16	    pathsToHighlight={[...PATHS_TO_HIGHLIGHT.DISKS_TAB, ...PATHS_TO_HIGHLIGHT.ENV_TAB]}
17	    resource={vm}
18	  >
19	    <Grid hasGutter>
20	      <GridItem>
21	        <PageSection variant={PageSectionVariants.light}>
22	          <DiskList vm={vm} vmi={vmi} />
23	        </PageSection>
24	      </GridItem>
25	      <GridItem>
26	        <Divider />
27	      </GridItem>
28	      <GridItem>
29	        <PageSection variant={PageSectionVariants.light}>
30	          <EnvironmentForm updateVM={onSubmitYAML} vm={vm} />
31	        </PageSection>
32	      </GridItem>
33	    </Grid>
34	  </SidebarEditor>
35	);
36	
37	export default StorageTab;

